 1	import React, { FC, useMemo } from 'react';
 2	
 3	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import SubTitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/SubTitleChartLabel';
 5	import TitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/TitleChartLabel';
 6	import ComponentReady from '@kubevirt-utils/components/Charts/ComponentReady/ComponentReady';
 7	import { getUtilizationQueries } from '@kubevirt-utils/components/Charts/utils/queries';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { getVMIPod } from '@kubevirt-utils/resources/vmi';
10	import {
11	  K8sResourceCommon,
12	  PrometheusEndpoint,
13	  usePrometheusPoll,
14	} from '@openshift-console/dynamic-plugin-sdk';
15	import { ChartDonutUtilization } from '@patternfly/react-charts';
16	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
17	
18	type CPUUtilProps = {
19	  pods: K8sResourceCommon[];
20	  vmi: V1VirtualMachineInstance;
21	};
22	
23	const CPUUtil: FC<CPUUtilProps> = ({ pods, vmi }) => {
24	  const { t } = useKubevirtTranslation();
25	  const vmiPod = useMemo(() => getVMIPod(vmi, pods), [pods, vmi]);
26	  const { currentTime, duration } = useDuration();
27	  const queries = useMemo(
28	    () => getUtilizationQueries({ duration, launcherPodName: vmiPod?.metadata?.name, obj: vmi }),
29	    [vmi, vmiPod, duration],
30	  );
31	
32	  const [dataCPURequested] = usePrometheusPoll({
33	    endpoint: PrometheusEndpoint?.QUERY,
34	    endTime: currentTime,
35	    namespace: vmi?.metadata?.namespace,
36	    query: queries.CPU_REQUESTED,
37	  });
38	
39	  const [dataCPUUsage] = usePrometheusPoll({
40	    endpoint: PrometheusEndpoint?.QUERY,
41	    endTime: currentTime,
42	    namespace: vmi?.metadata?.namespace,
43	    query: queries?.CPU_USAGE,
44	  });
45	
46	  const cpuUsage = +dataCPUUsage?.data?.result?.[0]?.value?.[1];
47	  const cpuRequested = +dataCPURequested?.data?.result?.[0]?.value?.[1];
48	  const averageCPUUsage = (cpuUsage / cpuRequested) * 100;
49	  const isReady = !Number.isNaN(cpuUsage) && !Number.isNaN(cpuRequested);
50	
51	  return (
52	    <div className="util">
53	      <div className="util-upper">
54	        <div className="util-title">{t('CPU')}</div>
55	        <div className="util-summary" data-test-id="util-summary-cpu">
56	          <div className="util-summary-value">{`${isReady ? cpuUsage?.toFixed(2) : 0}m`}</div>
57	          <div className="util-summary-text text-muted">
58	            <div>{t('Requested of ')}</div>
59	            <div>{`${isReady ? cpuRequested?.toFixed(2) : 0}m`}</div>
60	          </div>
61	        </div>
62	      </div>
63	      <div className="util-chart">
64	        <ComponentReady isReady={isReady}>
65	          <ChartDonutUtilization
66	            data={{
67	              x: t('CPU used'),
68	              y: (averageCPUUsage > 100 ? 100 : averageCPUUsage) || 0,
69	            }}
70	            animate
71	            constrainToVisibleArea
72	            labels={({ datum }) => (datum.x ? `${datum.x}: ${(cpuUsage || 0)?.toFixed(2)}m` : null)}
73	            style={{ labels: { fontSize: 20 } }}
74	            subTitle={t('Used')}
75	            subTitleComponent={<SubTitleChartLabel y={135} />}
76	            title={`${averageCPUUsage.toFixed(2) || 0}%`}
77	            titleComponent={<TitleChartLabel />}
78	          />
79	        </ComponentReady>
80	      </div>
81	    </div>
82	  );
83	};
84	
85	export default CPUUtil;

